function normalizeCustomerData(data) {
    if (Array.isArray(data)) {
        return data.map(customer => ({
            ...customer,
            id: customer.id || customer.__ID,
            __ID: customer.__ID || customer.id
        }));
    }
    return { ...data, id: data.id || data.__ID, __ID: data.__ID || data.id };
}

